{id:207, topic:"quantitative", difficulty:"medium", question:"A bag has 3 red, 4 blue, 5 green balls. Probability of drawing a blue ball:", options:["1/3","1/4","1/2","4/12"], answer:0, explanation:"P = 4/(3+4+5) = 4/12 = 1/3"},
{id:208, topic:"quantitative", difficulty:"medium", question:"The surface area of a sphere of radius 7 cm is (π=22/7):", options:["154 cm²","308 cm²","616 cm²","1232 cm²"], answer:2, explanation:"SA = 4πr² = 4×(22/7)×49 = 616 cm²"},
{id:209, topic:"quantitative", difficulty:"hard", question:"How many 3-digit numbers can be formed using digits 1,2,3,4,5 without repetition?", options:["60","120","125","150"], answer:0, explanation:"P(5,3) = 5×4×3 = 60"},
{id:210, topic:"quantitative", difficulty:"medium", question:"If log10(x) = 3, then x =?", options:["30","100","1000","10000"], answer:2, explanation:"log₁₀(x) = 3 → x = 10³ = 1000"},
{id:211, topic:"quantitative", difficulty:"easy", question:"The circumference of a circle with diameter 14 cm (π=22/7) is:", options:["22 cm","44 cm","88 cm","154 cm"], answer:1, explanation:"C = πd = (22/7)×14 = 44 cm"},
{id:212, topic:"quantitative", difficulty:"medium", question:"A sum doubles itself in 8 years at SI. The rate of interest is:", options:["10%","12.5%","15%","25%"], answer:1, explanation:"SI = P (doubles means SI=P). R = (P×100)/(P×8) = 12.5%"},
{id:213, topic:"quantitative", difficulty:"hard", question:"In a class of 60, 40 play cricket and 30 play football. 10 play neither. How many play both?", options:["10","15","20","25"], answer:2, explanation:"Playing at least one = 60−10 = 50. Both = 40+30−50 = 20"},
{id:214, topic:"quantitative", difficulty:"medium", question:"The ratio of areas of two circles whose radii are in ratio 2:3 is:", options:["2:3","4:9","8:27","4:6"], answer:1, explanation:"Area ratio = r₁²:r₂² = 4:9"},
{id:215, topic:"quantitative", difficulty:"easy", question:"What is 0.125 as a fraction?", options:["1/4","1/8","1/5","1/10"], answer:1, explanation:"0.125 = 125/1000 = 1/8"},

// --- Logical Reasoning: Advanced ---
{id:216, topic:"logical", difficulty:"medium", question:"If 'PENCIL' is coded as 'RGPEKN', then 'ERASER' is coded as:", options:["GTCUGT","GTCUFS","GTCUGT","GSCUGT"], answer:0, explanation:"Each letter +2: E→G, R→T, A→C, S→U, E→G, R→T = GTCUGT"},
{id:217, topic:"logical", difficulty:"medium", question:"A man is facing West. He turns 45° clockwise, then 90° anticlockwise. Which direction is he facing?", options:["North-West","South-West","North","North-East"], answer:1, explanation:"West=270°. +45° CW = 315° (NW). Then −90° ACW = 315°−90° = 225° = South-West."},
{id:218, topic:"logical", difficulty:"easy", question:"Find the missing: 3, 6, 11, 18, 27, ?", options:["36","38","40","35"], answer:1, explanation:"Differences: 3, 5, 7, 9, 11. Next = 27 + 11 = 38"},
{id:219, topic:"logical", difficulty:"medium", question:"P is Q's brother. R is Q's mother. S is R's father. T is S's mother. How is P related to T?", options:["Grandson","Great-grandson","Great-granddaughter","Grandfather"], answer:1, explanation:"P is Q's brother. Q's mother is R. R's father is S. S's mother is T. So P is T's great-grandson."},
{id:220, topic:"logical", difficulty:"easy", question:"Which number replaces '?': 1, 1, 2, 3, 5, 8, 13, ?", options:["18","20","21","26"], answer:2, explanation:"Fibonacci sequence: each number = sum of previous two. 8+13 = 21"},
{id:221, topic:"logical", difficulty:"medium", question:"If × means +, + means ÷, ÷ means −, − means ×, then 12 × 8 − 3 ÷ 4 + 2 = ?", options:["30","32","34","36"], answer:2, explanation:"Replace: 12 + 8 × 3 − 4 ÷ 2. BODMAS: 8×3=24, 4÷2=2. Then 12+24−2 = 34"},
{id:222, topic:"logical", difficulty:"medium", question:"In a certain code, A=2, B=4, C=6... What is the value of 'FACE'?", options:["28","30","32","36"], answer:1, explanation:"A=2, B=4, C=6, D=8, E=10, F=12. FACE = 12+2+6+10 = 30"},
{id:223, topic:"logical", difficulty:"hard", question:"Statement: All pens are pencils. Some pencils are erasers. Conclusion I: Some erasers are pens. II: Some pencils are pens.", options:["Only I","Only II","Both I and II","Neither"], answer:1, explanation:"All pens are pencils → Some pencils are pens (II follows). But erasers may not overlap with pens (I doesn't follow)."},
{id:224, topic:"logical", difficulty:"easy", question:"How many days are there in a leap year?", options:["364","365","366","367"], answer:2, explanation:"Leap year has 366 days (Feb has 29 days)."},
{id:225, topic:"logical", difficulty:"medium", question:"At 4:30, what angle do the clock hands make?", options:["30°","35°","40°","45°"], answer:3, explanation:"Angle = |30×4 − 5.5×30| = |120 − 165| = 45°"},

// --- Verbal Ability: More ---
{id:226, topic:"verbal", difficulty:"easy", question:"Synonym of 'Abundant':", options:["Scarce","Plentiful","Rare","Small"], answer:1, explanation:"Abundant means plentiful, copious, present in large quantity."},
{id:227, topic:"verbal", difficulty:"easy", question:"Antonym of 'Eloquent':", options:["Articulate","Fluent","Inarticulate","Expressive"], answer:2, explanation:"Eloquent means fluent/persuasive speaking. Inarticulate is the opposite."},
{id:228, topic:"verbal", difficulty:"medium", question:"Choose the correctly spelled word:", options:["Accomodation","Accommodation","Acomodation","Acommodation"], answer:1, explanation:"Correct spelling: Accommodation (double c, double m)"},
{id:229, topic:"verbal", difficulty:"medium", question:"'A person who collects stamps' is called:", options:["Numismatist","Philatelist","Archaeologist","Philanthropist"], answer:1, explanation:"Philatelist = stamp collector. Numismatist = coin collector."},
{id:230, topic:"verbal", difficulty:"easy", question:"Fill in: Neither Ram ___ Shyam was present.", options:["or","and","nor","but"], answer:2, explanation:"'Neither...nor' is the correct pair. Neither Ram nor Shyam."},
{id:231, topic:"verbal", difficulty:"medium", question:"'To burn the midnight oil' means:", options:["To waste oil","To work/study late at night","To burn something","To cook at night"], answer:1, explanation:"It means to work or study late into the night."},
{id:232, topic:"verbal", difficulty:"easy", question:"One who knows everything is called:", options:["Omnipresent","Omnipotent","Omnivore","Omniscient"], answer:3, explanation:"Omniscient = all-knowing. Omni = all, scient = knowing."},
{id:233, topic:"verbal", difficulty:"medium", question:"Choose the correct sentence:", options:["He has went to school","He has gone to school","He has go to school","He have gone to school"], answer:1, explanation:"Past participle of 'go' is 'gone'. He has gone to school."},
{id:234, topic:"verbal", difficulty:"medium", question:"Synonym of 'Pragmatic':", options:["Idealistic","Theoretical","Practical","Impractical"], answer:2, explanation:"Pragmatic means dealing with things sensibly and realistically; practical."},
{id:235, topic:"verbal", difficulty:"easy", question:"'Government by the people' is called:", options:["Autocracy","Democracy","Monarchy","Theocracy"], answer:1, explanation:"Democracy = government by the people (demos = people, kratos = rule)."},

// --- Programming: More Depth ---
{id:236, topic:"programming", difficulty:"medium", question:"What is the output of: System.out.println(10 + 20 + \"Hello\" + 10 + 20);", options:["30Hello1020","1020Hello1020","30Hello30","Error"], answer:0, explanation:"Left to right: 10+20=30, 30+\"Hello\"=\"30Hello\", +\"10\"+\"20\" = \"30Hello1020\""},
{id:237, topic:"programming", difficulty:"easy", question:"Which keyword is used to inherit a class in Java?", options:["implements","import","extends","inherits"], answer:2, explanation:"'extends' is used for class inheritance. 'implements' is for interfaces."},
{id:238, topic:"programming", difficulty:"medium", question:"What is the output? int x=5; printf(\"%d %d %d\", x++, x++, ++x);", options:["5 6 8","7 6 5","7 6 8","Undefined behavior"], answer:3, explanation:"Modifying a variable multiple times in the same expression is undefined behavior in C."},
{id:239, topic:"programming", difficulty:"medium", question:"What does 'static' keyword mean for a method in Java?", options:["Method can be overridden","Method belongs to the class, not instances","Method is private","Method runs automatically"], answer:1, explanation:"Static methods belong to the class and can be called without creating an object."},
{id:240, topic:"programming", difficulty:"easy", question:"Which data structure uses LIFO principle?", options:["Queue","Array","Stack","Linked List"], answer:2, explanation:"Stack uses Last In First Out (LIFO). Push/pop from the top."},
{id:241, topic:"programming", difficulty:"medium", question:"What is an abstract class?", options:["A class with all static methods","A class that cannot be instantiated and may have abstract methods","A class with no methods","A final class"], answer:1, explanation:"Abstract class can't be instantiated directly. It may contain abstract methods (without body) that subclasses must implement."},
{id:242, topic:"programming", difficulty:"hard", question:"Time complexity of binary search on a sorted array of n elements:", options:["O(n)","O(n²)","O(log n)","O(1)"], answer:2, explanation:"Binary search halves the search space each step → O(log n)."},
{id:243, topic:"programming", difficulty:"medium", question:"What is method overloading?", options:["Same method name in child class","Same method name with different parameters in same class","Calling method multiple times","None of these"], answer:1, explanation:"Overloading = same name, different parameter lists (compile-time polymorphism)."},
{id:244, topic:"programming", difficulty:"easy", question:"What is the default value of an int variable in Java?", options:["null","0","1","undefined"], answer:1, explanation:"Default value of int in Java is 0. For boolean it's false, for objects it's null."},
{id:245, topic:"programming", difficulty:"medium", question:"What is a constructor?", options:["A destructor","A special method called when an object is created","A static method","A final method"], answer:1, explanation:"Constructor initializes an object. Same name as class, no return type, called automatically."},

// --- DBMS: More ---
{id:246, topic:"dbms", difficulty:"easy", question:"Which SQL keyword is used to retrieve unique values?", options:["UNIQUE","DIFFERENT","DISTINCT","SEPARATE"], answer:2, explanation:"SELECT DISTINCT column_name FROM table — removes duplicates."},
{id:247, topic:"dbms", difficulty:"medium", question:"What is the difference between DELETE and TRUNCATE?", options:["No difference","DELETE is DML (row-by-row, can rollback), TRUNCATE is DDL (drops all, faster, can't rollback)","TRUNCATE deletes one row","DELETE is faster"], answer:1, explanation:"DELETE: DML, row-by-row, WHERE clause, can rollback. TRUNCATE: DDL, removes all rows, faster, resets auto-increment."},
{id:248, topic:"dbms", difficulty:"medium", question:"Which normal form removes transitive dependency?", options:["1NF","2NF","3NF","BCNF"], answer:2, explanation:"3NF: No transitive dependency (non-key attribute should not depend on another non-key attribute)."},
{id:249, topic:"dbms", difficulty:"easy", question:"What does the HAVING clause do?", options:["Filters individual rows","Filters groups after GROUP BY","Creates groups","Sorts results"], answer:1, explanation:"HAVING filters groups (used with GROUP BY). WHERE filters rows before grouping."},
{id:250, topic:"dbms", difficulty:"medium", question:"What is a VIEW in SQL?", options:["A physical table","A virtual table based on SELECT query result","An index","A stored procedure"], answer:1, explanation:"VIEW = virtual table created from a SELECT query. Doesn't store data physically."},
{id:251, topic:"dbms", difficulty:"hard", question:"What is the difference between RANK() and DENSE_RANK()?", options:["No difference","RANK skips numbers after ties, DENSE_RANK doesn't","DENSE_RANK is slower","RANK is not a function"], answer:1, explanation:"RANK: 1,2,2,4 (skips 3). DENSE_RANK: 1,2,2,3 (no gaps)."},
{id:252, topic:"dbms", difficulty:"easy", question:"Which command removes a table from the database?", options:["DELETE TABLE","REMOVE TABLE","DROP TABLE","CLEAR TABLE"], answer:2, explanation:"DROP TABLE table_name — permanently removes table and its data."},
{id:253, topic:"dbms", difficulty:"medium", question:"What type of JOIN returns all rows from both tables?", options:["INNER JOIN","LEFT JOIN","RIGHT JOIN","FULL OUTER JOIN"], answer:3, explanation:"FULL OUTER JOIN returns all rows from both tables, with NULLs where there's no match."},

// --- OS: More ---
{id:254, topic:"os", difficulty:"medium", question:"What is thrashing in OS?", options:["Fast processing","Excessive page faults causing system slowdown","A type of virus","Memory leak"], answer:1, explanation:"Thrashing occurs when the OS spends more time paging than executing, drastically reducing performance."},
{id:255, topic:"os", difficulty:"easy", question:"What does FCFS stand for in CPU scheduling?", options:["First Come Fast Serve","First Come First Served","Fast Compute First System","First CPU First Schedule"], answer:1, explanation:"FCFS = First Come First Served. Processes executed in arrival order."},
{id:256, topic:"os", difficulty:"medium", question:"In Round Robin scheduling, what happens when a process's time quantum expires?", options:["Process is terminated","Process is preempted and moved to end of ready queue","Process continues","System crashes"], answer:1, explanation:"When time quantum expires, the running process is preempted and placed at the end of the ready queue."},
{id:257, topic:"os", difficulty:"medium", question:"What is a semaphore?", options:["A type of process","A synchronization mechanism using integer variable with wait/signal operations","A scheduling algorithm","A memory type"], answer:1, explanation:"Semaphore = integer variable accessed via wait(P) and signal(V) operations for process synchronization."},
{id:258, topic:"os", difficulty:"easy", question:"What is paging in OS?", options:["Printing pages","Memory management scheme that divides memory into fixed-size pages","A file system","A process state"], answer:1, explanation:"Paging divides memory into fixed-size blocks (pages/frames) to avoid external fragmentation."},
{id:259, topic:"os", difficulty:"hard", question:"Banker's algorithm is used for:", options:["Memory management","Deadlock avoidance by checking safe state","CPU scheduling","File management"], answer:1, explanation:"Banker's Algorithm determines if granting a resource request will leave the system in a safe state."},

// --- Networking: More ---
{id:260, topic:"networking", difficulty:"easy", question:"What is the purpose of DNS?", options:["Data encryption","Translates domain names to IP addresses","File transfer","Email delivery"], answer:1, explanation:"DNS (Domain Name System) resolves human-readable domain names to IP addresses."},
{id:261, topic:"networking", difficulty:"medium", question:"Which layer of OSI model handles routing?", options:["Transport","Network","Data Link","Application"], answer:1, explanation:"Network layer (Layer 3) handles routing, IP addressing, and packet forwarding."},
{id:262, topic:"networking", difficulty:"easy", question:"What is the difference between hub and switch?", options:["No difference","Hub broadcasts to all ports, Switch sends to specific port using MAC","Switch is slower","Hub is smarter"], answer:1, explanation:"Hub: broadcasts to all (Layer 1). Switch: learns MAC addresses and forwards to specific port (Layer 2)."},
{id:263, topic:"networking", difficulty:"medium", question:"What is ARP used for?", options:["Routing","Resolving IP address to MAC address","DNS resolution","Encryption"], answer:1, explanation:"ARP (Address Resolution Protocol) maps IP addresses to MAC addresses on a local network."},
{id:264, topic:"networking", difficulty:"medium", question:"How many usable host addresses in a /28 subnet?", options:["14","16","30","32"], answer:0, explanation:"/28 = 4 host bits. 2⁴ = 16 − 2 (network + broadcast) = 14 usable hosts."},

// --- DSA: More ---
{id:265, topic:"dsa", difficulty:"easy", question:"What is the time complexity of accessing an element in an array by index?", options:["O(1)","O(n)","O(log n)","O(n²)"], answer:0, explanation:"Array access by index is O(1) — direct memory address calculation."},
{id:266, topic:"dsa", difficulty:"medium", question:"In a BST, the inorder traversal gives:", options:["Random order","Sorted ascending order","Reverse order","Level order"], answer:1, explanation:"Inorder traversal of BST (Left-Root-Right) always gives elements in sorted ascending order."},
{id:267, topic:"dsa", difficulty:"medium", question:"What is the worst-case time complexity of Quick Sort?", options:["O(n)","O(n log n)","O(n²)","O(log n)"], answer:2, explanation:"Worst case is O(n²) when pivot is always min/max (already sorted array with first/last pivot)."},
{id:268, topic:"dsa", difficulty:"easy", question:"Which traversal visits Root → Left → Right?", options:["Inorder","Preorder","Postorder","Level order"], answer:1, explanation:"Preorder: Root-Left-Right. Inorder: Left-Root-Right. Postorder: Left-Right-Root."},
{id:269, topic:"dsa", difficulty:"medium", question:"A complete binary tree with 15 nodes has how many leaf nodes?", options:["7","8","4","16"], answer:1, explanation:"In a complete binary tree, leaves = (n+1)/2 = 8. Internal nodes = 7."},
{id:270, topic:"dsa", difficulty:"hard", question:"Which data structure is used in BFS traversal of a graph?", options:["Stack","Queue","Heap","Array"], answer:1, explanation:"BFS uses a Queue to explore nodes level by level. DFS uses Stack/recursion."},

// --- More Quantitative ---
{id:271, topic:"quantitative", difficulty:"medium", question:"If the price of sugar is increased by 10%, by how much % must a family reduce consumption to keep expense same?", options:["9.09%","10%","11%","8%"], answer:0, explanation:"Reduction = (10/110)×100 = 9.09%. Formula: r/(100+r)×100"},
{id:272, topic:"quantitative", difficulty:"easy", question:"What is the mode of: 2, 3, 4, 4, 5, 5, 5, 6?", options:["3","4","5","6"], answer:2, explanation:"Mode = most frequent value = 5 (appears 3 times)."},
{id:273, topic:"quantitative", difficulty:"medium", question:"A shopkeeper sells at 10% loss. If he had sold for ₹100 more, he would have gained 10%. CP is:", options:["₹400","₹500","₹600","₹1000"], answer:1, explanation:"0.9×CP + 100 = 1.1×CP → 100 = 0.2×CP → CP = 500"},
{id:274, topic:"quantitative", difficulty:"medium", question:"The median of 5, 8, 3, 12, 7, 10, 1 is:", options:["5","7","8","10"], answer:1, explanation:"Sorted: 1,3,5,7,8,10,12. Middle value (4th) = 7"},
{id:275, topic:"quantitative", difficulty:"easy", question:"What is 15% of 800?", options:["100","110","120","130"], answer:2, explanation:"15% of 800 = (15/100)×800 = 120"},

// --- More Mixed ---
{id:276, topic:"programming", difficulty:"medium", question:"What is garbage collection?", options:["Deleting files","Automatic memory reclamation of unused objects","Disk cleanup","Cache clearing"], answer:1, explanation:"GC automatically frees memory occupied by objects that are no longer referenced."},
{id:277, topic:"programming", difficulty:"easy", question:"What is an interface in Java?", options:["A class","A blueprint with abstract methods that a class can implement","A variable","A loop"], answer:1, explanation:"Interface = contract of abstract methods. Classes implement interfaces. Supports multiple inheritance."},
{id:278, topic:"dbms", difficulty:"medium", question:"What is a deadlock in DBMS?", options:["Fast query","Two transactions waiting for each other's locks indefinitely","Index corruption","Connection timeout"], answer:1, explanation:"Deadlock: T1 holds lock A, waits for B. T2 holds lock B, waits for A. Neither can proceed."},
{id:279, topic:"logical", difficulty:"medium", question:"If APPLE is coded as 50 (A=1,P=16...), what is CODE?", options:["26","27","28","30"], answer:1, explanation:"C=3, O=15, D=4, E=5. Total = 3+15+4+5 = 27"},
{id:280, topic:"verbal", difficulty:"medium", question:"'That which cannot be read' is called:", options:["Inaudible","Illegible","Invisible","Indelible"], answer:1, explanation:"Illegible = cannot be read. Inaudible = cannot be heard. Invisible = cannot be seen."},

{id:281, topic:"quantitative", difficulty:"hard", question:"A tank is filled by pipe A in 4 hrs, pipe B in 6 hrs. Pipe C empties it in 12 hrs. If all open, time to fill:", options:["3 hrs","4 hrs","6 hrs","8 hrs"], answer:0, explanation:"Rate = 1/4 + 1/6 − 1/12. LCM=12: 3/12 + 2/12 − 1/12 = 4/12 = 1/3. Time = 3 hrs."},
{id:282, topic:"quantitative", difficulty:"medium", question:"The average of first 50 natural numbers is:", options:["25","25.5","26","50"], answer:1, explanation:"Average = Sum/n = [50×51/2]/50 = 51/2 = 25.5"},
{id:283, topic:"programming", difficulty:"medium", question:"What is the output of: print(type([])) in Python?", options:["<class 'tuple'>","<class 'list'>","<class 'dict'>","<class 'set'>"], answer:1, explanation:"[] creates an empty list. type([]) returns <class 'list'>."},
{id:284, topic:"dsa", difficulty:"medium", question:"What is the space complexity of merge sort?", options:["O(1)","O(log n)","O(n)","O(n²)"], answer:2, explanation:"Merge sort needs O(n) extra space for the temporary arrays during merging."},
{id:285, topic:"networking", difficulty:"medium", question:"What is NAT?", options:["Network Access Token","Network Address Translation — maps private IPs to public IPs","Network Analysis Tool","Network Authentication Type"], answer:1, explanation:"NAT translates private IP addresses to public IP addresses and vice versa for internet access."},
{id:286, topic:"os", difficulty:"medium", question:"What is the difference between process and thread?", options:["No difference","Process has own memory space (heavy); thread shares memory within process (lightweight)","Thread is a process","Process is lighter"], answer:1, explanation:"Process: independent, own address space. Thread: lightweight, shares process memory, faster context switch."},
{id:287, topic:"logical", difficulty:"easy", question:"What comes next: A, C, E, G, I, ?", options:["J","K","L","M"], answer:1, explanation:"Pattern: skip one letter each time. A(1), C(3), E(5), G(7), I(9), K(11)"},
{id:288, topic:"verbal", difficulty:"easy", question:"Antonym of 'Transparent':", options:["Clear","Opaque","Visible","Bright"], answer:1, explanation:"Transparent means see-through. Opaque means cannot see through."},
{id:289, topic:"quantitative", difficulty:"easy", question:"If a triangle has sides 3, 4, and 5, it is a:", options:["Equilateral","Isosceles","Right-angled","Obtuse"], answer:2, explanation:"3²+4² = 9+16 = 25 = 5². Pythagorean triplet → right-angled triangle."},
{id:290, topic:"programming", difficulty:"medium", question:"What is encapsulation?", options:["Hiding data by wrapping it with methods and controlling access via access modifiers","Inheriting from parent","Having many forms","Abstracting complexity"], answer:0, explanation:"Encapsulation = bundling data + methods + access control (private fields, public getters/setters)."},

{id:291, topic:"dbms", difficulty:"medium", question:"What is an index in a database?", options:["A primary key","A data structure that speeds up data retrieval at cost of extra storage","A foreign key","A view"], answer:1, explanation:"Index = B-tree/hash structure on columns for faster lookups. Trade-off: faster reads, slower writes, extra storage."},
{id:292, topic:"os", difficulty:"medium", question:"What is the difference between internal and external fragmentation?", options:["No difference","Internal: wasted space within allocated block; External: wasted space between allocated blocks","Both are same","External is inside blocks"], answer:1, explanation:"Internal: unused space within a partition. External: free memory scattered in small non-contiguous blocks."},
{id:293, topic:"networking", difficulty:"easy", question:"What is a MAC address?", options:["IP address","Unique 48-bit hardware address assigned to network interface card","A software address","A port number"], answer:1, explanation:"MAC = Media Access Control. 48-bit (6 bytes) hardware address. Format: AA:BB:CC:DD:EE:FF."},
{id:294, topic:"logical", difficulty:"medium", question:"If CLOUD = 59 (C=3,L=12,O=15,U=21,D=4), what is RAIN?", options:["42","43","44","45"], answer:0, explanation:"R=18, A=1, I=9, N=14. Total = 18+1+9+14 = 42"},
{id:295, topic:"quantitative", difficulty:"medium", question:"A car covers 432 km in 6 hours. How long to cover 648 km at the same speed?", options:["8 hrs","9 hrs","10 hrs","12 hrs"], answer:1, explanation:"Speed = 432/6 = 72 km/h. Time = 648/72 = 9 hours"},
{id:296, topic:"programming", difficulty:"hard", question:"What is the difference between deep copy and shallow copy?", options:["No difference","Shallow copies references only; deep copy clones the entire object including nested objects","Deep copy is faster","Shallow is more thorough"], answer:1, explanation:"Shallow: copies top-level, nested objects share references. Deep: recursively copies all nested objects."},
{id:297, topic:"dsa", difficulty:"medium", question:"What is a hash collision?", options:["Memory overflow","When two different keys produce the same hash value/index","A deadlock","A race condition"], answer:1, explanation:"Collision: different keys map to same bucket. Resolved by chaining (linked lists) or open addressing (probing)."},
{id:298, topic:"verbal", difficulty:"medium", question:"Choose the correct preposition: She is good ___ mathematics.", options:["in","at","on","with"], answer:1, explanation:"'Good at' is the correct collocation. She is good at mathematics."},
{id:299, topic:"quantitative", difficulty:"hard", question:"If (x−1)(x−2)(x−3) = 0 and x > 2, then x can be:", options:["1 only","2 only","3 only","1 or 3"], answer:2, explanation:"x−1=0 → x=1, x−2=0 → x=2, x−3=0 → x=3. Since x>2, only x=3."},
{id:300, topic:"programming", difficulty:"medium", question:"What is polymorphism in OOP?", options:["Data hiding","Code reuse through inheritance","Same interface behaving differently based on context","Breaking into modules"], answer:2, explanation:"Polymorphism = many forms. Compile-time (overloading) and runtime (overriding). Same method name, different behavior."},

// ===== NEW QUESTIONS — QUANTITATIVE APTITUDE (Q301-Q333) =====
{id:301, topic:"quantitative", difficulty:"easy", question:"If the price of an item is increased by 25%, by what percent must it be reduced to restore the original price?", options:["20%","25%","30%","15%"], answer:0, explanation:"Required decrease = (25/125)×100 = 20%. Formula: x/(100+x)×100"},
{id:302, topic:"quantitative", difficulty:"medium", question:"A sum becomes 3 times itself at simple interest in 8 years. What is the rate of interest?", options:["20%","25%","30%","12.5%"], answer:1, explanation:"SI = 2P (since amount = 3P). R = (SI×100)/(P×T) = (2×100)/8 = 25%"},
{id:303, topic:"quantitative", difficulty:"medium", question:"The diagonal of a rectangle is 13 cm and one side is 5 cm. What is the area?", options:["50 cm²","60 cm²","65 cm²","55 cm²"], answer:1, explanation:"Other side = √(13²−5²) = √(169−25) = √144 = 12. Area = 5×12 = 60 cm²"},
{id:304, topic:"quantitative", difficulty:"easy", question:"If the cost of 15 pens is ₹150, what is the cost of 8 pens?", options:["₹60","₹70","₹80","₹90"], answer:2, explanation:"Cost per pen = 150/15 = ₹10. Cost of 8 = 8×10 = ₹80"},
{id:305, topic:"quantitative", difficulty:"medium", question:"A mixture contains alcohol and water in 4:3. If 10 litres of water is added, ratio becomes 4:5. Original quantity of mixture?", options:["35 L","49 L","28 L","42 L"], answer:0, explanation:"Alcohol = 4x, Water = 3x. After adding 10: 4x/(3x+10) = 4/5 → 20x = 12x+40 → 8x=40 → x=5. Total = 7×5 = 35 litres."},
{id:306, topic:"quantitative", difficulty:"medium", question:"A train 250 m long passes a bridge 750 m long in 40 seconds. Speed of train in km/h?", options:["72","80","90","100"], answer:2, explanation:"Total distance = 250+750 = 1000 m in 40 s. Speed = 1000/40 = 25 m/s = 25×18/5 = 90 km/h"},
{id:307, topic:"quantitative", difficulty:"easy", question:"What is the smallest number divisible by both 12 and 18?", options:["24","36","72","108"], answer:1, explanation:"LCM(12,18) = 36"},
{id:308, topic:"quantitative", difficulty:"medium", question:"If 40% of a number is 200, what is 60% of that number?", options:["250","300","350","400"], answer:1, explanation:"Number = 200/0.4 = 500. 60% of 500 = 300"},
{id:309, topic:"quantitative", difficulty:"medium", question:"A man rows upstream at 6 km/h and downstream at 10 km/h. Speed of the man in still water?", options:["7 km/h","8 km/h","9 km/h","10 km/h"], answer:1, explanation:"Speed in still water = (10+6)/2 = 8 km/h"},
{id:310, topic:"quantitative", difficulty:"hard", question:"In how many ways can 5 people sit around a circular table?", options:["120","24","60","12"], answer:1, explanation:"Circular permutation = (n-1)! = 4! = 24"},
{id:311, topic:"quantitative", difficulty:"medium", question:"What is the sum of all angles in a hexagon?", options:["540°","720°","900°","1080°"], answer:1, explanation:"Sum = (n-2)×180 = (6-2)×180 = 4×180 = 720°"},
{id:312, topic:"quantitative", difficulty:"easy", question:"If A:B = 2:3 and B:C = 4:5, find A:B:C.", options:["8:12:15","2:3:5","4:6:5","8:12:10"], answer:0, explanation:"Make B common: A:B = 8:12, B:C = 12:15. So A:B:C = 8:12:15"},
{id:313, topic:"quantitative", difficulty:"medium", question:"A sells to B at 20% profit, B sells to C at 10% profit. If C pays ₹660, what did A pay?", options:["₹400","₹450","₹500","₹550"], answer:2, explanation:"B's CP = 660/1.1 = 600. A's CP = 600/1.2 = 500"},
{id:314, topic:"quantitative", difficulty:"medium", question:"Two trains running same direction at 40 km/h and 20 km/h. First train (200 m long) passes second in:", options:["24 s","30 s","36 s","40 s"], answer:2, explanation:"Relative speed = 40-20 = 20 km/h = 50/9 m/s. Time = 200/(50/9) = 200×9/50 = 36 s"},
{id:315, topic:"quantitative", difficulty:"easy", question:"What is 15% of 400 + 25% of 200?", options:["100","110","120","130"], answer:1, explanation:"15% of 400 = 60. 25% of 200 = 50. Total = 110"},
{id:316, topic:"quantitative", difficulty:"medium", question:"If log₂(x) = 5, then x = ?", options:["10","16","32","64"], answer:2, explanation:"log₂(x) = 5 → x = 2⁵ = 32"},
{id:317, topic:"quantitative", difficulty:"hard", question:"How many 3-digit numbers are divisible by 7?", options:["128","129","130","131"], answer:0, explanation:"First 3-digit ÷7: ceil(100/7)=15 → 15×7=105. Last: floor(999/7)=142 → 142×7=994. Count = 142−15+1 = 128."},
{id:318, topic:"quantitative", difficulty:"easy", question:"The average of first 10 natural numbers is:", options:["5","5.5","6","6.5"], answer:1, explanation:"Sum = 10×11/2 = 55. Average = 55/10 = 5.5"},
{id:319, topic:"quantitative", difficulty:"medium", question:"If the radius of a circle is doubled, its area becomes:", options:["Double","Triple","4 times","8 times"], answer:2, explanation:"Area = πr². If r→2r: Area = π(2r)² = 4πr². So 4 times."},
{id:320, topic:"quantitative", difficulty:"medium", question:"Two dice are thrown. What is the probability of getting a sum of 7?", options:["1/6","5/36","7/36","1/9"], answer:0, explanation:"Favorable: (1,6),(2,5),(3,4),(4,3),(5,2),(6,1) = 6. Total = 36. P = 6/36 = 1/6"},
{id:321, topic:"quantitative", difficulty:"hard", question:"How many ways to arrange letters of word BANANA?", options:["60","120","360","720"], answer:0, explanation:"6!/(3!×2!) = 720/(6×2) = 60. Three A's and two N's repeat."},
{id:322, topic:"quantitative", difficulty:"medium", question:"If CI on a sum is ₹820 and SI is ₹800 for 2 years, find the rate:", options:["5%","4%","6%","10%"], answer:0, explanation:"CI - SI for 2 years = PR²/100² = P×R²/10000. Also SI = 2PR/100 = 800 → PR=40000. CI-SI = 20 = PR²/10000 = 40000×R/10000 = 4R. R = 5%."},
{id:323, topic:"quantitative", difficulty:"easy", question:"If selling price is ₹450 and loss is 10%, what is the cost price?", options:["₹480","₹490","₹500","₹510"], answer:2, explanation:"CP = SP/(1-Loss%) = 450/0.9 = 500"},
{id:324, topic:"quantitative", difficulty:"medium", question:"A can do 1/3 of a work in 5 days, B can do 2/5 of the work in 10 days. Together they finish in:", options:["7.5 days","9.375 days","10 days","12 days"], answer:1, explanation:"A's full rate = (1/3)/5 = 1/15 per day. B's full rate = (2/5)/10 = 1/25 per day. Together = 1/15+1/25 = 5/75+3/75 = 8/75. Time = 75/8 = 9.375 days."},
{id:325, topic:"quantitative", difficulty:"medium", question:"What is the area of equilateral triangle with side 6 cm?", options:["9√3","12√3","15√3","18√3"], answer:0, explanation:"Area = (√3/4)×a² = (√3/4)×36 = 9√3 cm²"},
{id:326, topic:"quantitative", difficulty:"easy", question:"Convert 45 km/h to m/s:", options:["10.5 m/s","12 m/s","12.5 m/s","15 m/s"], answer:2, explanation:"45 × 5/18 = 225/18 = 12.5 m/s"},
{id:327, topic:"quantitative", difficulty:"medium", question:"A shopkeeper marks goods 40% above CP and gives 20% discount. His profit percentage is:", options:["10%","12%","15%","20%"], answer:1, explanation:"Let CP=100. MP=140. SP=140×0.8=112. Profit=12%"},
{id:328, topic:"quantitative", difficulty:"hard", question:"The product of two numbers is 120 and their HCF is 2. How many such pairs exist?", options:["2","3","4","5"], answer:2, explanation:"Let numbers = 2a, 2b where HCF(a,b)=1 and 4ab=120 → ab=30. Co-prime factor pairs of 30: (1,30)✓, (2,15)✓, (3,10)✓, (5,6)✓ = 4 pairs."},
{id:329, topic:"quantitative", difficulty:"easy", question:"What is the value of √(144 + 25)?", options:["12","13","14","15"], answer:1, explanation:"√(144+25) = √169 = 13"},
{id:330, topic:"quantitative", difficulty:"medium", question:"In a class of 50, average age is 20. If teacher's age included, average becomes 21. Teacher's age is:", options:["50","55","60","71"], answer:3, explanation:"Sum of students = 50×20 = 1000. New sum = 51×21 = 1071. Teacher = 1071-1000 = 71"},
{id:331, topic:"quantitative", difficulty:"medium", question:"A cistern has 3 pipes: A fills in 10 hrs, B fills in 15 hrs, C empties in 30 hrs. Time to fill when all open?", options:["6 hrs","7.5 hrs","8 hrs","10 hrs"], answer:1, explanation:"Net rate = 1/10 + 1/15 - 1/30 = 3/30+2/30-1/30 = 4/30 = 2/15. Time = 15/2 = 7.5 hrs"},
{id:332, topic:"quantitative", difficulty:"hard", question:"From a pack of 52 cards, probability of drawing a king or a heart:", options:["4/13","17/52","16/52","5/13"], answer:0, explanation:"P(King)+P(Heart)-P(King of Hearts) = 4/52+13/52-1/52 = 16/52 = 4/13"},
{id:333, topic:"quantitative", difficulty:"medium", question:"A number when divided by 5 gives remainder 3, when divided by 7 gives remainder 4. Smallest such number:", options:["18","23","28","53"], answer:0, explanation:"Numbers with rem 3 when ÷5: 3,8,13,18,23... Numbers with rem 4 when ÷7: 4,11,18,25... Common = 18"},

// ===== NEW QUESTIONS — VERBAL ABILITY (Q334-Q356) =====
{id:334, topic:"verbal", difficulty:"easy", question:"Choose the synonym for 'Prudent':", options:["Reckless","Wise","Foolish","Hasty"], answer:1, explanation:"Prudent = wise, showing care and thought for the future."},
{id:335, topic:"verbal", difficulty:"easy", question:"Choose the antonym for 'Vivacious':", options:["Lively","Dull","Energetic","Spirited"], answer:1, explanation:"Vivacious = full of life/energy. Opposite = dull."},
{id:336, topic:"verbal", difficulty:"medium", question:"Choose the correctly punctuated sentence:", options:["Its a beautiful day.","It's a beautiful day.","Its' a beautiful day.","It's, a beautiful day."], answer:1, explanation:"It's = it is (contraction). Its = possessive form."},
{id:337, topic:"verbal", difficulty:"easy", question:"One word substitution for 'A person who cannot read or write':", options:["Illiterate","Ignorant","Naive","Amateur"], answer:0, explanation:"Illiterate = unable to read or write."},
{id:338, topic:"verbal", difficulty:"medium", question:"Identify the error: 'The committee have decided to postpone the meeting.'", options:["committee","have","decided","postpone"], answer:1, explanation:"'Committee' is collective noun treated as singular → 'has decided'."},
{id:339, topic:"verbal", difficulty:"easy", question:"'To let the cat out of the bag' means:", options:["To free a cat","To reveal a secret","To cause trouble","To be careless"], answer:1, explanation:"To let the cat out of the bag = to reveal a secret unintentionally."},
{id:340, topic:"verbal", difficulty:"medium", question:"Choose the correct word: The weather will definitely _____ our plans.", options:["affect","effect","infect","defect"], answer:0, explanation:"Affect (verb) = to influence. Effect (noun) = result."},
{id:341, topic:"verbal", difficulty:"easy", question:"Choose the synonym for 'Meticulous':", options:["Careless","Detailed","Lazy","Quick"], answer:1, explanation:"Meticulous = very careful and precise, paying attention to detail."},
{id:342, topic:"verbal", difficulty:"medium", question:"Choose the correct form: 'If I _____ rich, I would travel the world.'", options:["am","was","were","be"], answer:2, explanation:"Subjunctive mood: 'If I were...' for hypothetical situations."},
{id:343, topic:"verbal", difficulty:"easy", question:"One word for 'A government ruled by a king or queen':", options:["Democracy","Monarchy","Oligarchy","Theocracy"], answer:1, explanation:"Monarchy = government by a monarch (king/queen)."},
{id:344, topic:"verbal", difficulty:"medium", question:"Choose the antonym for 'Gregarious':", options:["Social","Reclusive","Friendly","Outgoing"], answer:1, explanation:"Gregarious = fond of company. Reclusive = avoiding others."},
{id:345, topic:"verbal", difficulty:"easy", question:"Fill in the blank: He insisted _____ going alone.", options:["in","on","at","for"], answer:1, explanation:"'Insist on' is the correct phrasal verb."},
{id:346, topic:"verbal", difficulty:"medium", question:"Meaning of 'A white elephant':", options:["A rare animal","A costly but useless possession","Something valuable","A gift"], answer:1, explanation:"White elephant = something expensive to maintain but of little use."},
{id:347, topic:"verbal", difficulty:"easy", question:"Choose the correctly spelled word:", options:["Occurence","Occurrence","Occurrance","Ocurrence"], answer:1, explanation:"Occurrence — double 'c', double 'r'."},
{id:348, topic:"verbal", difficulty:"medium", question:"Active voice of 'The cake was eaten by the children':", options:["The children ate the cake","The children eat the cake","The cake ate the children","The children were eating the cake"], answer:0, explanation:"Active: Subject (children) + verb (ate) + object (cake)."},
{id:349, topic:"verbal", difficulty:"easy", question:"Choose the synonym for 'Ubiquitous':", options:["Rare","Everywhere","Unique","Remote"], answer:1, explanation:"Ubiquitous = present, appearing, or found everywhere."},
{id:350, topic:"verbal", difficulty:"medium", question:"Identify the error: 'Neither Ram nor his friends was present.'", options:["Neither","nor","was","present"], answer:2, explanation:"When subjects joined by 'neither...nor', verb agrees with the nearer subject (friends = plural → were)."},
{id:351, topic:"verbal", difficulty:"easy", question:"One word for 'Study of stars and celestial bodies':", options:["Astrology","Astronomy","Astrophysics","Cosmology"], answer:1, explanation:"Astronomy = scientific study of celestial objects and phenomena."},
{id:352, topic:"verbal", difficulty:"medium", question:"'To be in the same boat' means:", options:["To be on a ship","To be in the same difficult situation","To agree","To travel together"], answer:1, explanation:"To be in the same boat = to be in the same unpleasant situation."},
{id:353, topic:"verbal", difficulty:"easy", question:"Choose the correct preposition: She is allergic _____ dust.", options:["to","with","from","by"], answer:0, explanation:"'Allergic to' is the correct collocation."},
{id:354, topic:"verbal", difficulty:"medium", question:"Choose the word most nearly opposite to 'Obsolete':", options:["Ancient","Modern","Outdated","Useless"], answer:1, explanation:"Obsolete = no longer in use. Modern = current, up-to-date."},
{id:355, topic:"verbal", difficulty:"easy", question:"Choose the correctly spelled word:", options:["Convinience","Convenience","Conveniance","Conveneince"], answer:1, explanation:"Convenience — remember: con-ven-ience."},
{id:356, topic:"verbal", difficulty:"medium", question:"'Pulling someone's leg' means:", options:["Hurting someone","Teasing or joking with someone","Helping someone","Tripping someone"], answer:1, explanation:"Pulling someone's leg = teasing/joking, not being serious."},

// ===== NEW QUESTIONS — LOGICAL REASONING (Q357-Q377) =====
{id:357, topic:"logical", difficulty:"easy", question:"If TEACHER = 7, STUDENT = 7, then CLASSROOM = ?", options:["7","8","9","10"], answer:2, explanation:"Count the letters: TEACHER=7, STUDENT=7, CLASSROOM=9"},
{id:358, topic:"logical", difficulty:"medium", question:"What is the angle between clock hands at 3:30?", options:["75°","90°","80°","85°"], answer:0, explanation:"At 3:30: Hour hand = 3×30 + 30×0.5 = 105°. Minute hand = 30×6 = 180°. Angle = 180-105 = 75°"},
{id:359, topic:"logical", difficulty:"medium", question:"A is taller than B. C is shorter than D. D is taller than A. Who is the tallest?", options:["A","B","C","D"], answer:3, explanation:"D > A > B, and D > C. So D is tallest."},
{id:360, topic:"logical", difficulty:"easy", question:"If Monday is day 1, what day number is Thursday?", options:["3","4","5","6"], answer:1, explanation:"Mon=1, Tue=2, Wed=3, Thu=4"},
{id:361, topic:"logical", difficulty:"medium", question:"Find the missing number: 4, 9, 25, 49, 121, ?", options:["144","169","196","225"], answer:1, explanation:"These are squares of primes: 2²=4, 3²=9, 5²=25, 7²=49, 11²=121, 13²=169"},
{id:362, topic:"logical", difficulty:"medium", question:"If P denotes +, Q denotes ×, R denotes ÷, S denotes −, then 8Q3P4S2R1 = ?", options:["26","28","30","32"], answer:0, explanation:"Replace: 8×3+4−2÷1. BODMAS: 8×3=24, 2÷1=2. Then 24+4−2=26."},
{id:363, topic:"logical", difficulty:"easy", question:"In a certain code, RED = 27, GREEN = 49. What is BLUE?", options:["36","40","38","42"], answer:1, explanation:"RED: R(18)+E(5)+D(4)=27. GREEN: G(7)+R(18)+E(5)+E(5)+N(14)=49. BLUE: B(2)+L(12)+U(21)+E(5)=40"},
{id:364, topic:"logical", difficulty:"hard", question:"Five friends P, Q, R, S, T sit in a row. P is not at either end. Q is to the right of R. S is at one end. T is next to P. How many arrangements possible?", options:["4","6","8","12"], answer:0, explanation:"S at end, P not at end (middle 3 positions), T next to P, Q right of R. Constraints narrow it to 4 valid arrangements."},
{id:365, topic:"logical", difficulty:"medium", question:"How many triangles can be formed using 6 points where no 3 are collinear?", options:["10","15","20","30"], answer:2, explanation:"⁶C₃ = 6!/(3!×3!) = 720/(6×6) = 20"},
{id:366, topic:"logical", difficulty:"easy", question:"Complete: STV, UWX, YAB, ?", options:["CDE","BCD","CDF","DEF"], answer:0, explanation:"Each group starts 4 letters after previous start: S(+4)→U(+4)→Y(+4)→C. Pattern: CDE"},
{id:367, topic:"logical", difficulty:"medium", question:"A is B's mother. B is C's brother. C is D's sister. D is E's father. How is A related to E?", options:["Mother","Grandmother","Great-grandmother","Aunt"], answer:1, explanation:"A is mother of B. B is brother of C. So A is mother of C too. C is sister of D. So A is mother of D. D is father of E. So A is grandmother of E."},
{id:368, topic:"logical", difficulty:"medium", question:"If 1st Jan 2024 is Monday, what day is 1st March 2024?", options:["Thursday","Friday","Saturday","Wednesday"], answer:1, explanation:"Jan has 31 days, Feb has 29 (2024 leap year). Total = 31+29 = 60 days from Jan 1. 60÷7 = 8 weeks + 4 days. Mon + 4 = Friday."},
{id:369, topic:"logical", difficulty:"easy", question:"Which number does not belong? 8, 27, 64, 100, 125", options:["27","64","100","125"], answer:2, explanation:"8=2³, 27=3³, 64=4³, 125=5³. 100 is not a perfect cube (it's 10²)."},
{id:370, topic:"logical", difficulty:"medium", question:"Mirror image: If you stand facing North and turn 90° clockwise, then 180° anticlockwise, you face:", options:["North","South","East","West"], answer:3, explanation:"Start: North. 90° clockwise → East. 180° anticlockwise → West."},
{id:371, topic:"logical", difficulty:"medium", question:"Statement: All books are pages. All pages are words. Conclusion: All books are words.", options:["True","False","Cannot determine","Partially true"], answer:0, explanation:"All books are pages and all pages are words → All books are words. This follows logically."},
{id:372, topic:"logical", difficulty:"easy", question:"Find the next: A1, B2, C3, D4, ?", options:["E5","F6","E4","D5"], answer:0, explanation:"Letter advances by 1, number advances by 1. E5"},
{id:373, topic:"logical", difficulty:"medium", question:"6 people shake hands with each other exactly once. Total handshakes?", options:["12","15","18","30"], answer:1, explanation:"⁶C₂ = 6×5/2 = 15"},
{id:374, topic:"logical", difficulty:"medium", question:"A clock shows 3:15. What is the angle between hour and minute hands?", options:["0°","7.5°","15°","22.5°"], answer:1, explanation:"Hour hand = 3×30 + 15×0.5 = 97.5°. Minute hand = 15×6 = 90°. Angle = 97.5-90 = 7.5°"},
{id:375, topic:"logical", difficulty:"easy", question:"If MOBILE = 42, what is PHONE?", options:["51","52","55","57"], answer:2, explanation:"Pattern: MOBILE has 6 letters → 6×7=42. PHONE has 5 letters → 5×11=55. Code = letters × next_prime."},
{id:376, topic:"logical", difficulty:"hard", question:"In a family, A is married to B. C is son of A. D is sister of C. E is husband of D. F is son of E. How is F related to A?", options:["Son","Grandson","Nephew","Grand-nephew"], answer:1, explanation:"A married to B. C is son of A. D is sister of C, so D is daughter of A. E is husband of D. F is son of E and D. So F is grandson of A."},
{id:377, topic:"logical", difficulty:"medium", question:"If South-East becomes North, what does North-West become?", options:["South","East","West","North-East"], answer:0, explanation:"Directions are rotated 135° clockwise (SE→N). So NW rotated 135° clockwise = South."},

// ===== NEW QUESTIONS — PROGRAMMING (Q378-Q392) =====
{id:378, topic:"programming", difficulty:"easy", question:"What is the output? int x=10; printf('%d', x%3);", options:["0","1","3","10"], answer:1, explanation:"10 % 3 = 1 (remainder when 10 divided by 3)"},
{id:379, topic:"programming", difficulty:"medium", question:"In Java, which collection does NOT allow duplicates?", options:["ArrayList","LinkedList","HashSet","Vector"], answer:2, explanation:"HashSet implements Set interface, which does not allow duplicate elements."},
{id:380, topic:"programming", difficulty:"medium", question:"What is the output?\nfor(int i=0; i<5; i++) {\n  if(i==3) continue;\n  printf('%d ', i);\n}", options:["0 1 2 3 4","0 1 2 4","0 1 2","0 1 2 3"], answer:1, explanation:"continue skips the rest of loop body for i=3. Prints: 0 1 2 4"},
{id:381, topic:"programming", difficulty:"easy", question:"What is a constructor in OOP?", options:["A destructor","A special method called when object is created","A static method","A getter method"], answer:1, explanation:"Constructor is automatically called when an object is instantiated, used to initialize the object."},
{id:382, topic:"programming", difficulty:"medium", question:"In Python, what does 'self' refer to?", options:["The class itself","The current instance of the class","A global variable","A module"], answer:1, explanation:"'self' refers to the current instance, allowing access to instance variables and methods."},
{id:383, topic:"programming", difficulty:"hard", question:"What is the output?\nint a=5, b=10;\nprintf('%d', a+++b);", options:["15","16","Error","Undefined"], answer:0, explanation:"Parsed as (a++) + b = 5 + 10 = 15. a becomes 6 after this expression."},
{id:384, topic:"programming", difficulty:"medium", question:"What is method overloading?", options:["Overriding parent method","Multiple methods with same name but different parameters in same class","Calling method multiple times","Creating abstract methods"], answer:1, explanation:"Overloading = same method name, different parameter types/count. Compile-time polymorphism."},
{id:385, topic:"programming", difficulty:"easy", question:"What is the output? print(type(3.14)) in Python", options:["<class 'int'>","<class 'float'>","<class 'str'>","<class 'double'>"], answer:1, explanation:"3.14 is a floating-point number, so type is float in Python."},
{id:386, topic:"programming", difficulty:"medium", question:"What is a segmentation fault?", options:["Syntax error","Runtime error: accessing memory you shouldn't","Logical error","Compilation error"], answer:1, explanation:"Segfault occurs when program tries to read/write memory it doesn't have access to (null pointer, buffer overflow)."},
{id:387, topic:"programming", difficulty:"medium", question:"In Java, what keyword makes a variable constant?", options:["static","const","final","volatile"], answer:2, explanation:"'final' prevents reassignment. For reference types, the reference can't change (but object contents can)."},
{id:388, topic:"programming", difficulty:"easy", question:"What is a linked list?", options:["An array with fixed size","A linear data structure where elements are connected via pointers","A tree structure","A hash table"], answer:1, explanation:"Linked list: each node contains data + pointer to next node. Dynamic size, O(1) insertion."},
{id:389, topic:"programming", difficulty:"medium", question:"Difference between while and do-while loop?", options:["No difference","while checks condition first; do-while executes at least once","do-while is faster","while runs forever"], answer:1, explanation:"while: check then execute (may execute 0 times). do-while: execute then check (at least once)."},
{id:390, topic:"programming", difficulty:"hard", question:"What is a memory leak?", options:["When memory is full","When program allocates memory but never frees it, causing progressive memory growth","When files are corrupted","When RAM fails"], answer:1, explanation:"Memory leak: allocated memory that is no longer referenced but not freed. Common in C/C++ without proper free()/delete."},
{id:391, topic:"programming", difficulty:"medium", question:"What is the output of: System.out.println(10 + 20 + \"Hello\");", options:["1020Hello","30Hello","Hello1020","Error"], answer:1, explanation:"Left to right: 10+20=30 (int addition), then 30+\"Hello\" = \"30Hello\" (string concatenation)."},
{id:392, topic:"programming", difficulty:"easy", question:"What does NULL mean in programming?", options:["Zero","Empty string","Pointer that points to nothing/no valid memory","False"], answer:2, explanation:"NULL = a pointer/reference that intentionally points to nothing. Different from 0 or empty string."},

// ===== NEW QUESTIONS — DSA (Q393-Q404) =====
{id:393, topic:"dsa", difficulty:"easy", question:"What is the time complexity of inserting at the beginning of a linked list?", options:["O(1)","O(n)","O(log n)","O(n²)"], answer:0, explanation:"Insert at head: create node, point to old head, update head. O(1) constant time."},
{id:394, topic:"dsa", difficulty:"medium", question:"What is the worst case time complexity of Quick Sort?", options:["O(n log n)","O(n²)","O(n)","O(log n)"], answer:1, explanation:"Worst case occurs when pivot is always the smallest/largest element (already sorted array). O(n²)."},
{id:395, topic:"dsa", difficulty:"medium", question:"Which data structure is best for implementing a priority queue?", options:["Array","Linked List","Heap","Stack"], answer:2, explanation:"Heap (min-heap or max-heap) provides O(log n) insert and O(1) access to min/max. Ideal for priority queue."},
{id:396, topic:"dsa", difficulty:"easy", question:"What traversal of BST gives sorted output?", options:["Preorder","Postorder","Inorder","Level order"], answer:2, explanation:"Inorder traversal (Left → Root → Right) of a BST visits nodes in ascending order."},
{id:397, topic:"dsa", difficulty:"medium", question:"What is the space complexity of merge sort?", options:["O(1)","O(log n)","O(n)","O(n²)"], answer:2, explanation:"Merge sort requires O(n) extra space for the temporary arrays during merging."},
{id:398, topic:"dsa", difficulty:"easy", question:"Maximum number of nodes in a binary tree of height h:", options:["2h","h²","2^(h+1) - 1","2^h"], answer:2, explanation:"A complete binary tree of height h has at most 2^(h+1) - 1 nodes (root at h=0)."},
{id:399, topic:"dsa", difficulty:"medium", question:"What is the time complexity to search in a balanced BST?", options:["O(1)","O(log n)","O(n)","O(n log n)"], answer:1, explanation:"Balanced BST has height O(log n). Search follows a path from root to leaf: O(log n)."},
{id:400, topic:"dsa", difficulty:"medium", question:"Which graph algorithm detects negative weight cycles?", options:["Dijkstra","BFS","Bellman-Ford","Prim's"], answer:2, explanation:"Bellman-Ford can handle negative weights and detect negative cycles (if after V-1 iterations, values still update)."},
{id:401, topic:"dsa", difficulty:"easy", question:"Stack operations push and pop have time complexity:", options:["O(n)","O(1)","O(log n)","O(n²)"], answer:1, explanation:"Push and pop both operate on the top of the stack — O(1) constant time."},
{id:402, topic:"dsa", difficulty:"medium", question:"What is the difference between BFS and DFS?", options:["No difference","BFS uses queue (level-by-level), DFS uses stack (depth-first)","BFS is always faster","DFS uses queue"], answer:1, explanation:"BFS: Queue, explores neighbors first (breadth). DFS: Stack/recursion, explores depth first."},
{id:403, topic:"dsa", difficulty:"hard", question:"Time complexity of building a heap from an array of n elements:", options:["O(n log n)","O(n)","O(n²)","O(log n)"], answer:1, explanation:"Bottom-up heap construction (heapify) is O(n), not O(n log n). Mathematical proof using geometric series."},
{id:404, topic:"dsa", difficulty:"medium", question:"What data structure is used for LRU Cache?", options:["Array + Stack","HashMap + Doubly Linked List","Queue + Tree","Two Stacks"], answer:1, explanation:"LRU Cache: HashMap for O(1) lookup + Doubly Linked List for O(1) insert/remove to maintain access order."}
